const data = $input.first().json.body || $input.first().json;

let score = 0;
const raisons = [];

// Budget
const budget = parseInt(data.budget) || 0;
if (budget >= 3000) { score += 40; raisons.push('Budget ≥ 3000€ (+40)'); }
else if (budget >= 1500) { score += 25; raisons.push('Budget ≥ 1500€ (+25)'); }
else if (budget >= 500) { score += 10; raisons.push('Budget ≥ 500€ (+10)'); }

// Secteur
const secteursPrioritaires = ['restaurant', 'pizzeria', 'coiffure', 'boutique', 'ecommerce'];
const secteur = (data.secteur || '').toLowerCase();
if (secteursPrioritaires.includes(secteur)) { score += 20; raisons.push('Secteur prioritaire : ' + secteur + ' (+20)'); }
else if (secteur) { score += 10; raisons.push('Secteur : ' + secteur + ' (+10)'); }

// Telephone
if (data.telephone && data.telephone.length > 8) { score += 15; raisons.push('Telephone fourni (+15)'); }

// Message
if (data.message && data.message.length > 100) { score += 15; raisons.push('Message detaille (+15)'); }
else if (data.message && data.message.length > 30) { score += 5; raisons.push('Message court (+5)'); }

// Urgence
const motsUrgence = ['urgent', 'rapidement', 'vite', 'des que possible', 'asap'];
if (motsUrgence.some(m => (data.message || '').toLowerCase().includes(m))) {
  score += 10;
  raisons.push('Urgence detectee (+10)');
}

let priorite, emoji;
if (score >= 70) { priorite = 'HOT'; emoji = '🔥'; }
else if (score >= 40) { priorite = 'WARM'; emoji = '⚡'; }
else { priorite = 'COLD'; emoji = '🧊'; }

return [{
  json: {
    nom: data.nom || data.name || 'Inconnu',
    email: data.email || '',
    telephone: data.telephone || data.phone || 'Non renseigne',
    secteur: data.secteur || 'Non precise',
    message: data.message || data.description || '',
    budget: data.budget || 'Non precise',
    score,
    priorite,
    emoji,
    raisons: raisons.join(' | '),
    dateReception: new Date().toLocaleString('fr-FR', { timeZone: 'Indian/Reunion' })
  }
}];

